using System.Collections.Generic;\nusing UnityEngine;\n\npublic class MarkerManager : MonoBehaviour {\n    private List<GameObject> markers = new List<GameObject>();\n    \n    // Create a new marker at a given position\n    public GameObject CreateMarker(Vector3 position) {\n        GameObject marker = new GameObject("Marker");\n        marker.transform.position = position;\n        markers.Add(marker);\n        return marker;\n    }\n    \n    // Retrieve a marker by index\n    public GameObject RetrieveMarker(int index) {\n        if (index < 0 || index >= markers.Count) {\n            Debug.LogError("Marker index out of range.");\n            return null;\n        }\n        return markers[index];\n    }\n    \n    // Remove a marker by index\n    public void RemoveMarker(int index) {\n        if (index < 0 || index >= markers.Count) {\n            Debug.LogError("Marker index out of range.");\n            return;\n        }\n        GameObject markerToRemove = markers[index];\n        markers.RemoveAt(index);\n        Destroy(markerToRemove);\n    }\n    \n    // List all markers\n    public List<GameObject> GetAllMarkers() {\n        return new List<GameObject>(markers);\n    }\n}